import * as React from 'react';
import type { InternalSelectProps } from '../../select/internal.interface';
import type { TreeConfig, TreeNodeConfig } from '../../tree';
import { genDoublyTreeNodeMap, traverseTreeConfig } from '../../tree';
import type { CascaderSelectorProps } from '../interface';

function transformCascaderOptions2TreeData(options: TreeNodeConfig[]): TreeConfig {
  return options.map(o => {
    const { children, label, ...restProps } = o;
    return {
      ...restProps,
      label,
      // FIXME: optionLabelProp 允许指定让 title 作为 label
      // 但其实就算外头不传 title, 这里也会把 label 赋值给 title
      // 在之后的 getCascaderLabel 之类的逻辑里头又把 title 作为 label 使用
      // 后面的逻辑在有 label 的时候应该优先使用 label, 没有 label 才使用 title
      // 而 title 的值又是 label
      // 所以这里的 title 没啥用
      title: label,
      children: children ? transformCascaderOptions2TreeData(children) : undefined,
    };
  });
}

export function useCascaderData(props: Required<Pick<CascaderSelectorProps, 'options'>>) {
  const { options } = props;
  const treeData = React.useMemo(() => transformCascaderOptions2TreeData(options), [options]);

  const internalOptions = React.useMemo(() => {
    const _options: InternalSelectProps<string, TreeNodeConfig>['options'] = [];
    traverseTreeConfig(treeData, node => {
      _options.push(node);
    });
    return _options;
  }, [treeData]);

  // ======== 创建一个带索引的 tree node 双向链表 ========
  const { doublyTreeNodeList, doublyTreeNodeMap } = React.useMemo(() => genDoublyTreeNodeMap(treeData), [treeData]);

  return {
    internalOptions,
    doublyTreeNodeList,
    doublyTreeNodeMap,
  };
}
